import json

# Load troubled companies data
troubled_companies = locals()['var_functions.query_db:2']

# Create a dictionary mapping symbol to company info
company_info = {}
for company in troubled_companies:
    symbol = company['Symbol']
    company_info[symbol] = {
        'name': company['Company Description'].split('.')[0],  # Get company name
        'status': company['Financial Status']
    }

# Filter to only truly troubled companies (status codes indicating deficient/delinquent)
troubled_codes = ['D', 'E', 'Q', 'G', 'H', 'J', 'K']
filtered_companies = {symbol: info for symbol, info in company_info.items() 
                     if info['status'] in troubled_codes}

# Generate a summary of what we found
print("__RESULT__:")
print(json.dumps({
    'total_found': len(troubled_companies),
    'troubled_only': len(filtered_companies),
    'symbols': list(filtered_companies.keys())
}))

